```js
const delay = (ms, v) =>
  new Promise((r) => setTimeout(() => r(v), ms));

async function sequential() {
  const results = [];
  for (const n of [10, 20, 30]) {
    results.push(await delay(n, n * 2));
  }
  console.log("sequential", results.join(","));
}
async function parallel() {
  const results = await Promise.all(
    [10, 20, 30].map((n) => delay(n, n * 2))
  );
  console.log("parallel", results.join(","));
}
sequential();
parallel();
```

