```js
let attempts = 0;
async function flaky() {
  attempts++;
  if (attempts < 3) throw new Error("fail");
  return "ok";
}
async function retry(fn, times) {
  let lastError;
  for (let i = 0; i < times; i++) {
    try {
      return await fn();
    } catch (e) {
      lastError = e;
    }
  }
  throw lastError;
}
retry(flaky, 5).then((v) => console.log(v, attempts));
```

